import { formatTrademarkSymbolsInHtml } from "@/lib/textFormatting";
import { useState, useEffect, useCallback, useMemo, useRef } from "react";
import { useTranslation } from "react-i18next";
import { Collapsible, CollapsibleContent, CollapsibleTrigger } from "@/components/ui/collapsible";
import { ChevronDown, Building2 } from "lucide-react";
import { useBrand, ContentBlock } from "@/hooks/useBrands";
import { supabase } from "@/integrations/supabase/client";


interface BrandAboutSectionProps {
  brandId: string;
  /** When set to a language code, auto-triggers translation */
  autoTranslateLang?: string | null;
}

export function BrandAboutSection({ brandId, autoTranslateLang }: BrandAboutSectionProps) {
  const { t, i18n } = useTranslation();
  const [isOpen, setIsOpen] = useState(false);
  const [translatedHtml, setTranslatedHtml] = useState<string | null>(null);
  const [autoTranslatedLang, setAutoTranslatedLang] = useState<string | null>(null);
  const autoAttempted = useRef(false);
  const { data: brand, isLoading } = useBrand(brandId);

  // Get localized intro based on current language
  const getLocalizedIntro = useCallback(() => {
    if (!brand) return null;
    switch (i18n.language) {
      case "zh":
        return brand.intro_zh;
      case "pt":
        return brand.intro_pt;
      default:
        return brand.intro_en || brand.intro_zh;
    }
  }, [brand, i18n.language]);

  // Get localized content from content blocks
  const getLocalizedBlockContent = useCallback((block: ContentBlock) => {
    switch (i18n.language) {
      case "zh":
        return block.content_zh;
      case "pt":
        return block.content_pt;
      default:
        return block.content_en || block.content_zh;
    }
  }, [i18n.language]);

  const intro = getLocalizedIntro();
  const hasContentBlocks = brand?.content_blocks && brand.content_blocks.length > 0;

  // Build raw text for translation
  const getRawTextForTranslation = useCallback((): string => {
    if (!brand) return '';
    if (hasContentBlocks) {
      return brand.content_blocks!
        .filter(b => b.type === "text")
        .map(b => getLocalizedBlockContent(b))
        .filter(Boolean)
        .join('\n')
        .replace(/<[^>]*>/g, '');
    }
    return (intro || '').replace(/<[^>]*>/g, '');
  }, [brand, hasContentBlocks, getLocalizedBlockContent, intro]);

  const handleTranslation = (translated: string | null) => {
    if (!translated) {
      setTranslatedHtml(null);
      setAutoTranslatedLang(null);
      return;
    }
    setTranslatedHtml(translated.replace(/\n/g, '<br>'));
  };

  // Auto-translate on mount when user's language differs from content
  useEffect(() => {
    if (autoAttempted.current) return;
    if (!brand) return;
    
    const rawText = getRawTextForTranslation();
    if (!rawText.trim()) return;

    // Detect content language: if brand has zh content and user is zh, skip
    const userLang = i18n.language;
    // Check if content is predominantly Chinese
    const chineseChars = rawText.match(/[\u4e00-\u9fff\u3400-\u4dbf]/g);
    const totalChars = rawText.replace(/\s/g, "").length;
    const isChinese = chineseChars && totalChars > 0 && chineseChars.length / totalChars > 0.6;
    
    if (userLang === "zh" && isChinese) return;
    // If user is pt and content came from pt field, skip
    if (userLang === "pt" && brand.intro_pt && intro === brand.intro_pt) return;
    // If user is en and content came from en field, skip  
    if (userLang !== "zh" && userLang !== "pt" && brand.intro_en && intro === brand.intro_en) return;

    autoAttempted.current = true;
    const doTranslate = async () => {
      try {
        const { data, error } = await supabase.functions.invoke('translate-content', {
          body: { text: rawText, targetLang: userLang }
        });
        if (!error && data?.translatedText) {
          setTranslatedHtml(data.translatedText.replace(/\n/g, '<br>'));
          setAutoTranslatedLang(userLang);
        }
      } catch {}
    };
    doTranslate();
  }, [brand, i18n.language, getRawTextForTranslation, intro]);

  // Auto-translate when page-level translate is triggered
  useEffect(() => {
    if (!autoTranslateLang || autoTranslateLang === autoTranslatedLang) return;
    if (!brand) return;
    
    const rawText = getRawTextForTranslation();
    if (!rawText.trim()) return;

    const doTranslate = async () => {
      try {
        const { data, error } = await supabase.functions.invoke('translate-content', {
          body: { text: rawText, targetLang: autoTranslateLang }
        });
        if (!error && data?.translatedText) {
          setTranslatedHtml(data.translatedText.replace(/\n/g, '<br>'));
          setAutoTranslatedLang(autoTranslateLang);
          setIsOpen(true);
        }
      } catch {}
    };
    doTranslate();
  }, [autoTranslateLang, brand, autoTranslatedLang, getRawTextForTranslation]);

  // Reset when autoTranslateLang is cleared (show original)
  useEffect(() => {
    if (!autoTranslateLang && autoTranslatedLang) {
      setTranslatedHtml(null);
      setAutoTranslatedLang(null);
    }
  }, [autoTranslateLang, autoTranslatedLang]);

  if (isLoading || !brand) return null;
  if (!intro && !hasContentBlocks) return null;
  return (
    <Collapsible
      open={isOpen}
      onOpenChange={setIsOpen}
      className="mt-4"
    >
      <CollapsibleTrigger className="w-full">
        <div className="flex items-center justify-between p-3 rounded-lg bg-muted/50 hover:bg-muted/80 transition-colors">
          <div className="flex items-center gap-2">
            <Building2 className="w-5 h-5 text-primary" />
            <span className="font-medium">{t("brand.aboutUs")}</span>
          </div>
          <ChevronDown 
            className={`w-5 h-5 text-muted-foreground transition-transform ${isOpen ? 'rotate-180' : ''}`} 
          />
        </div>
      </CollapsibleTrigger>
      
      <CollapsibleContent>
        <div className="p-4 mt-2 rounded-lg bg-muted/30">
          {/* Show translated content if available */}
          {translatedHtml ? (
            <div 
              className="text-muted-foreground prose prose-sm dark:prose-invert max-w-none [&_*]:!text-inherit [&_a]:!text-primary [&_a]:underline"
              dangerouslySetInnerHTML={{ __html: translatedHtml }}
            />
          ) : (
            <>
              {/* Content Blocks - optimized layout */}
              <div className="space-y-4">
                {hasContentBlocks && brand.content_blocks!.map((block, index) => {
                  const content = getLocalizedBlockContent(block);
                  const isFirstImage = block.type === "image" && index === 0;
                  const isLastImage = block.type === "image" && index === brand.content_blocks!.length - 1;
                  
                  return (
                    <div key={block.id}>
                      {block.type === "text" && content && (
                        <div 
                          className="text-muted-foreground prose prose-sm dark:prose-invert max-w-none [&_*]:!text-inherit [&_a]:!text-primary [&_a]:underline"
                          dangerouslySetInnerHTML={{ __html: formatTrademarkSymbolsInHtml(content) }}
                        />
                      )}
                      {block.type === "image" && block.url && (
                        <div className="flex justify-start">
                          <img 
                            src={block.url} 
                            alt={block.alt || ""}
                            className={
                              isFirstImage 
                                ? "w-16 h-16 object-contain rounded-lg" 
                                : isLastImage 
                                  ? "h-12 w-auto object-contain opacity-80" 
                                  : "max-w-[120px] max-h-24 object-contain rounded-lg"
                            }
                          />
                        </div>
                      )}
                    </div>
                  );
                })}
              </div>

              {/* Brand Intro - if no content blocks */}
              {intro && !hasContentBlocks && (
                <div 
                  className="text-muted-foreground prose prose-sm dark:prose-invert max-w-none [&_*]:!text-inherit [&_a]:!text-primary [&_a]:underline"
                  dangerouslySetInnerHTML={{ __html: formatTrademarkSymbolsInHtml(intro) }}
                />
              )}
            </>
          )}

          {/* Images still shown even when translated */}
          {translatedHtml && hasContentBlocks && brand.content_blocks!
            .filter(b => b.type === "image" && b.url)
            .map((block, index, arr) => (
              <div key={block.id} className="flex justify-start mt-4">
                <img 
                  src={block.url!} 
                  alt={block.alt || ""}
                  className={
                    index === 0 
                      ? "w-16 h-16 object-contain rounded-lg" 
                      : index === arr.length - 1 
                        ? "h-12 w-auto object-contain opacity-80" 
                        : "max-w-[120px] max-h-24 object-contain rounded-lg"
                  }
                />
              </div>
            ))
          }

        </div>
      </CollapsibleContent>
    </Collapsible>
  );
}
