interface GhostRestaurantHeroProps {
  restaurant: any;
  localizedRestaurant: any;
  onBack: () => void;
  user: any;
  isFavorite: boolean;
  onToggleFavorite: () => void;
  onShare: () => void;
  onReport: () => void;
  showEditButton?: boolean;
  editButton?: React.ReactNode;
  reportButton?: React.ReactNode;
  /** Translated name override */
  translatedName?: string | null;
  /** Translated description override */
  translatedDescription?: string | null;
  /** Translated owner bio override */
  translatedOwnerBio?: string | null;
  /** Whether translation is in progress */
  isTranslating?: boolean;
  /** Whether translation is currently shown */
  showTranslation?: boolean;
  /** Callback to trigger translation */
  onTranslate?: () => void;
}

// Collapsible Food Philosophy sub-component with dynamic overflow detection
const FOOD_PHILOSOPHY_MAX_HEIGHT = 240; // ~15em, same as brand story

const FoodPhilosophySection = ({ foodDescription, cleanFoodDesc }: { foodDescription: string; cleanFoodDesc: string }) => {
  const { t } = useTranslation();
  const [isExpanded, setIsExpanded] = useState(false);
  const [isOverflowing, setIsOverflowing] = useState(false);
  const contentRef = useRef<HTMLDivElement>(null);

  const checkOverflow = useCallback(() => {
    if (contentRef.current) {
      setIsOverflowing(contentRef.current.scrollHeight > FOOD_PHILOSOPHY_MAX_HEIGHT);
    }
  }, []);

  useEffect(() => {
    checkOverflow();
    window.addEventListener('resize', checkOverflow);
    return () => window.removeEventListener('resize', checkOverflow);
  }, [checkOverflow, foodDescription]);

  return (
    <div className="space-y-2 md:space-y-3 bg-muted/50 rounded-xl p-4 md:p-5 lg:p-6 border border-border/30">
      <h3 className="text-base md:text-lg font-semibold text-foreground flex items-center gap-2">
        <Quote className="w-4 h-4 md:w-5 md:h-5 text-primary rotate-180" />
        {t("restaurants.foodPhilosophy", "美食哲学")}
      </h3>
      <div className="relative">
        <div 
          ref={contentRef}
          className={`text-sm md:text-base text-muted-foreground leading-relaxed prose prose-sm dark:prose-invert max-w-none [&_*]:!text-muted-foreground [&_a]:!text-primary [&_a]:underline [&_p]:my-2 overflow-hidden transition-all duration-300`}
          style={isOverflowing && !isExpanded ? { maxHeight: `${FOOD_PHILOSOPHY_MAX_HEIGHT}px` } : undefined}
          dangerouslySetInnerHTML={{ __html: foodDescription }}
        />
        {isOverflowing && !isExpanded && (
          <div className="absolute bottom-0 left-0 right-0 h-8 bg-gradient-to-t from-muted/50 to-transparent" />
        )}
      </div>
      {isOverflowing && (
        <button
          onClick={() => setIsExpanded(!isExpanded)}
          className="flex items-center gap-1 text-xs text-primary hover:text-primary/80 transition-colors font-medium"
        >
          {isExpanded ? t("common.collapse", "收起") : t("common.expand", "展开")}
          <ChevronDown className={`w-3.5 h-3.5 transition-transform ${isExpanded ? 'rotate-180' : ''}`} />
        </button>
      )}
    </div>
  );
};

/** Signature dish area: shows first chef_recommended_dish if available, else cover image */
const SignatureDishWithNeijing = ({ restaurant, localizedRestaurant }: { restaurant: any; localizedRestaurant: any }) => {
  const { t, i18n } = useTranslation();
  const lang = i18n.language;
  const [dish, setDish] = useState<any>(null);
  const [neijingExpanded, setNeijingExpanded] = useState(false);
  const [neijingTranslation, setNeijingTranslation] = useState<{ text: string; showTranslated: boolean } | null>(null);
  const [isTranslatingNeijing, setIsTranslatingNeijing] = useState(false);

  useEffect(() => {
    supabase
      .from("chef_recommended_dishes" as any)
      .select("*")
      .eq("restaurant_id", restaurant.id)
      .order("sort_order")
      .limit(1)
      .then(({ data }) => {
        if (data && data.length > 0) setDish(data[0]);
      });
  }, [restaurant.id]);

  const getField = (obj: any, field: string) => {
    if (field === "neijing") {
      return obj["neijing_zh"] || obj["neijing_en"] || obj["neijing_pt"] || "";
    }
    const value = obj[`${field}_${lang}`];
    if (value) return value;
    return obj[`${field}_en`] || obj[`${field}_zh`] || obj[`${field}_pt`] || "";
  };

  const handleTranslateNeijing = async () => {
    if (neijingTranslation) {
      setNeijingTranslation(prev => prev ? { ...prev, showTranslated: !prev.showTranslated } : null);
      return;
    }
    const neijingZh = getField(dish, "neijing");
    if (!neijingZh) return;
    setIsTranslatingNeijing(true);
    try {
      const { data, error } = await supabase.functions.invoke('translate-content', {
        body: { text: neijingZh, targetLang: lang }
      });
      if (!error && data?.translatedText) {
        setNeijingTranslation({ text: data.translatedText, showTranslated: true });
      }
    } catch {}
    setIsTranslatingNeijing(false);
  };

  const isCoreLang = lang === "zh";
  const imageUrl = dish?.image_url || restaurant.cover_image_url || restaurant.image_url || "https://images.unsplash.com/photo-1517248135467-4c7edcad34c4?w=800&q=80";
  const neijingOriginal = dish ? getField(dish, "neijing") : "";
  const displayNeijing = neijingTranslation?.showTranslated ? neijingTranslation.text : neijingOriginal;

  return (
    <div className="space-y-3 md:flex md:flex-col md:h-full">
      <div className="relative aspect-square md:aspect-auto md:flex-1 md:min-h-[320px] w-full max-w-md md:max-w-none mx-auto md:mx-0 overflow-hidden rounded-xl shadow-lg group">
        <img
          src={imageUrl}
          alt={dish ? getField(dish, "dish_name") : localizedRestaurant.name}
          className="w-full h-full object-cover transition-transform duration-500 group-hover:scale-105"
        />
        <div className="absolute inset-0 bg-gradient-to-t from-black/20 via-transparent to-transparent" />
        {dish && (
          <div className="absolute bottom-0 left-0 right-0 p-3 md:p-4 bg-gradient-to-t from-black/60 to-transparent">
            <p className="text-white text-sm md:text-base font-semibold">
              🍽️ {getField(dish, "dish_name")}
            </p>
            <p className="text-white/80 text-xs md:text-sm mt-0.5">
              <span className="line-clamp-2">{getField(dish, "description")}</span>
              {!neijingExpanded && (
                <button
                  onClick={(e) => { e.stopPropagation(); setNeijingExpanded(true); }}
                  className="inline-flex items-center gap-0.5 ml-1 text-white font-medium underline underline-offset-2 hover:text-white/90"
                >
                  {t("common.details", "Details")}
                  <ChevronRight className="w-3 h-3" />
                </button>
              )}
            </p>
          </div>
        )}
      </div>
      {dish && neijingOriginal && !neijingExpanded && (
        <div className="max-w-md md:max-w-none mx-auto md:mx-0">
          <button
            onClick={() => setNeijingExpanded(true)}
            className="w-full flex items-center justify-center gap-1.5 py-2.5 rounded-lg text-sm font-medium text-primary hover:bg-primary/5 transition-colors"
          >
            {t("common.learnMore", "Learn More")}
            <ChevronDown className="w-4 h-4" />
          </button>
        </div>
      )}
      {dish && neijingOriginal && neijingExpanded && (
        <div className="bg-muted/30 border border-border/30 rounded-2xl p-5 max-w-md md:max-w-none mx-auto md:mx-0 animate-in fade-in slide-in-from-top-2 duration-300 space-y-3">
          <div className="flex items-center justify-between">
            <p className="text-sm font-bold text-foreground flex items-center gap-1.5">
              <span>📜</span>
              {t("chef.neijingInterpretation", "Huangdi Neijing Interpretation")}
            </p>
            {!isCoreLang && (
              <button
                onClick={(e) => { e.stopPropagation(); handleTranslateNeijing(); }}
                disabled={isTranslatingNeijing}
                className="inline-flex items-center gap-1 px-2 py-0.5 rounded text-[11px] font-medium text-primary hover:bg-primary/10 transition-colors disabled:opacity-50"
              >
                {isTranslatingNeijing ? (
                  <Loader2 className="w-3 h-3 animate-spin" />
                ) : (
                  <Languages className="w-3 h-3" />
                )}
                {isTranslatingNeijing
                  ? t("common.translating", "翻译中...")
                  : neijingTranslation?.showTranslated
                    ? t("common.showOriginal", "显示原文")
                    : t("common.translate", "翻译")}
              </button>
            )}
          </div>
          <p className="text-sm leading-[1.9] text-foreground font-medium">
            {displayNeijing}
          </p>
          {getField(dish, "description") && (
            <div className="pt-3 border-t border-foreground/10">
              <p className="text-xs font-bold text-foreground mb-1.5">🍽️ {t("chef.dishDetails", "Dish Details")}</p>
              <p className="text-sm leading-relaxed text-foreground/80">
                {getField(dish, "description")}
              </p>
            </div>
          )}
          <button
            onClick={() => setNeijingExpanded(false)}
            className="flex items-center gap-1 text-xs text-primary hover:text-primary/80 transition-colors font-medium"
          >
            <ChevronUp className="w-3.5 h-3.5" />
            {t("common.collapse", "Collapse")}
          </button>
        </div>
      )}
    </div>
  );
};

export const GhostRestaurantHero = ({
  restaurant,
  localizedRestaurant,
  onBack,
  user,
  isFavorite,
  onToggleFavorite,
  onShare,
  showEditButton,
  editButton,
  reportButton,
  translatedName,
  translatedDescription,
  translatedOwnerBio,
  isTranslating,
  showTranslation,
  onTranslate,
}: GhostRestaurantHeroProps) => {
  const { t, i18n } = useTranslation();
  const { getLocalizedField } = useLocalizedContent();
  const { isWebView, isIOSWebView } = useEnvironment();
  
  const [videoModalOpen, setVideoModalOpen] = useState(false);
  const [avatarPreviewOpen, setAvatarPreviewOpen] = useState(false);
  const [videoReady, setVideoReady] = useState(false);
  const [videoError, setVideoError] = useState(false);
  const videoRef = useRef<HTMLVideoElement>(null);
  const [manualBioTranslation, setManualBioTranslation] = useState<{ text: string; showTranslated: boolean } | null>(null);
  const [isTranslatingBio, setIsTranslatingBio] = useState(false);
  
  const rawOwnerBio = getLocalizedField(restaurant, "owner_bio") || restaurant.owner_bio;
  const ownerBio = translatedOwnerBio || rawOwnerBio;
  const isCoreLang = i18n.language === "zh";

  const handleTranslateBio = async () => {
    if (manualBioTranslation) {
      setManualBioTranslation(prev => prev ? { ...prev, showTranslated: !prev.showTranslated } : null);
      return;
    }
    if (!rawOwnerBio) return;
    setIsTranslatingBio(true);
    try {
      const { data, error } = await supabase.functions.invoke('translate-content', {
        body: { text: rawOwnerBio, targetLang: i18n.language }
      });
      if (!error && data?.translatedText) {
        setManualBioTranslation({ text: data.translatedText, showTranslated: true });
      }
    } catch {}
    setIsTranslatingBio(false);
  };

  const displayBio = manualBioTranslation?.showTranslated ? manualBioTranslation.text : ownerBio;
  const foodDescription = translatedDescription || localizedRestaurant.description;
  const avatarFallback = localizedRestaurant.name?.charAt(0)?.toUpperCase() || "主";

  // Check if banner should be video
  const isVideoBanner = restaurant.banner_media_type === 'video' && restaurant.promo_video_url;
  const bannerImage = restaurant.banner_url || restaurant.image_url || "https://images.unsplash.com/photo-1517248135467-4c7edcad34c4?w=1200&q=80";
  const videoPoster = restaurant.promo_video_poster || bannerImage;

  // Track if autoplay failed (for WebView fallback)
  const [autoplayFailed, setAutoplayFailed] = useState(false);
  const maxAutoplayAttempts = 3;

  // Strip HTML and truncate for preview
  const stripHtml = (html: string) => html?.replace(/<[^>]*>/g, '') || '';
  
  // Truncate bio for preview
  const truncatedBio = displayBio && displayBio.length > 100 
    ? displayBio.substring(0, 100) + "..." 
    : displayBio;
  const shouldShowViewMore = displayBio && displayBio.length > 100;

  // Clean food description
  const cleanFoodDesc = stripHtml(foodDescription);
  const truncatedFoodDesc = cleanFoodDesc && cleanFoodDesc.length > 120 
    ? cleanFoodDesc.substring(0, 120) + "..." 
    : cleanFoodDesc;

  // Intersection Observer to pause video when out of view
  const videoContainerRef = useRef<HTMLDivElement>(null);
  
  const handleVisibilityChange = useCallback((isVisible: boolean) => {
    if (!videoRef.current || !isVideoBanner || autoplayFailed) return;
    
    if (isVisible) {
      videoRef.current.play().catch(() => {});
    } else {
      videoRef.current.pause();
    }
  }, [isVideoBanner, autoplayFailed]);

  // Aggressive autoplay attempt function for WebView compatibility
  const attemptAutoplay = useCallback(async (video: HTMLVideoElement): Promise<boolean> => {
    try {
      // Ensure video is muted (required for autoplay)
      video.muted = true;
      video.volume = 0;
      
      // Try to play
      await video.play();
      return true;
    } catch (err) {
      console.warn('Video autoplay attempt failed:', err);
      return false;
    }
  }, []);

  // Handle video auto-play for iOS Safari and WebView compatibility
  useEffect(() => {
    if (!isVideoBanner || !videoRef.current) return;
    
    const video = videoRef.current;
    let attempts = 0;
    let timeoutId: ReturnType<typeof setTimeout>;
    let isMounted = true;
    
    const tryAutoplay = async () => {
      if (!isMounted || attempts >= maxAutoplayAttempts) {
        if (isMounted && attempts >= maxAutoplayAttempts) {
          setAutoplayFailed(true);
          setVideoReady(true);
        }
        return;
      }
      
      attempts++;
      const success = await attemptAutoplay(video);
      
      if (success && isMounted) {
        setVideoReady(true);
        setAutoplayFailed(false);
      } else if (isMounted && attempts < maxAutoplayAttempts) {
        // Retry after delay
        timeoutId = setTimeout(tryAutoplay, 500);
      } else if (isMounted) {
        setAutoplayFailed(true);
        setVideoReady(true);
      }
    };

    const handleLoadedData = () => {
      tryAutoplay();
    };

    const handleError = () => {
      if (isMounted) setVideoError(true);
    };

    // Start attempts based on current state
    if (video.readyState >= 2) {
      // HAVE_CURRENT_DATA or higher
      tryAutoplay();
    } else {
      video.addEventListener('loadeddata', handleLoadedData);
    }
    
    video.addEventListener('error', handleError);

    return () => {
      isMounted = false;
      clearTimeout(timeoutId);
      video.removeEventListener('loadeddata', handleLoadedData);
      video.removeEventListener('error', handleError);
    };
  }, [isVideoBanner, attemptAutoplay]);

  // Intersection Observer for pause on scroll
  useEffect(() => {
    if (!isVideoBanner || autoplayFailed || !videoContainerRef.current) return;

    const observer = new IntersectionObserver(
      (entries) => {
        entries.forEach((entry) => {
          handleVisibilityChange(entry.isIntersecting);
        });
      },
      { threshold: 0.1 } // Pause when less than 10% visible
    );

    observer.observe(videoContainerRef.current);

    return () => {
      observer.disconnect();
    };
  }, [isVideoBanner, autoplayFailed, handleVisibilityChange]);

  const handleBannerClick = () => {
    if (isVideoBanner && restaurant.promo_video_url) {
      // If autoplay failed, try to play inline first on user interaction
      if (autoplayFailed && videoRef.current) {
        const video = videoRef.current;
        video.muted = true;
        video.play().then(() => {
          setAutoplayFailed(false);
          setVideoReady(true);
        }).catch(() => {
          // If still can't play, open modal
          setVideoModalOpen(true);
        });
      } else {
        setVideoModalOpen(true);
      }
    }
  };

  return (
    <div className="relative">
      {/* Full-width Hero - Background Banner (Video or Image) */}
      <div 
        ref={videoContainerRef}
        className="relative h-[33vh] md:h-[40vh] overflow-hidden bg-muted cursor-pointer group"
        onClick={handleBannerClick}
      >
        {/* Video Banner - try autoplay, fallback to static if it fails */}
        {isVideoBanner && !videoError ? (
          <>
            {/* Poster image as loading fallback or when autoplay fails */}
            <img
              src={videoPoster}
              alt={localizedRestaurant.name}
              className={`absolute inset-0 w-full h-full object-cover transition-opacity duration-500 ${videoReady && !autoplayFailed ? 'opacity-0' : 'opacity-100'}`}
              loading="eager"
            />
            {/* Video element - always present but hidden when autoplay failed */}
            <video
              ref={videoRef}
              src={restaurant.promo_video_url}
              poster={videoPoster}
              className={`absolute inset-0 w-full h-full object-cover transition-opacity duration-500 ${videoReady && !autoplayFailed ? 'opacity-100' : 'opacity-0'}`}
              autoPlay
              muted
              loop
              playsInline
              // @ts-ignore - webkit-playsinline for iOS
              webkit-playsinline="true"
              // @ts-ignore - x5-playsinline for WeChat/QQ WebView
              x5-playsinline="true"
              // @ts-ignore - x5-video-player-type for inline play in WeChat
              x5-video-player-type="h5"
            />
          </>
        ) : (
          /* Static Image Banner (fallback or image mode) */
          <img
            src={bannerImage}
            alt={localizedRestaurant.name}
            className="w-full h-full object-cover"
            loading="eager"
          />
        )}

        {/* Gradient Overlay */}
        <div className="absolute inset-0 bg-gradient-to-t from-background/90 via-background/20 to-transparent" />

        {/* Video Play Button Overlay - always visible when autoplay failed */}
        {isVideoBanner && (
          <div className="absolute inset-0 flex items-center justify-center pointer-events-none">
            <div className={`w-16 h-16 md:w-20 md:h-20 rounded-full bg-white/20 backdrop-blur-sm flex items-center justify-center border border-white/30 transition-opacity duration-300 pointer-events-auto cursor-pointer ${autoplayFailed ? 'opacity-100' : 'opacity-0 group-hover:opacity-100'}`}>
              <Play className="w-8 h-8 md:w-10 md:h-10 text-white ml-1" fill="white" />
            </div>
          </div>
        )}

        {/* Navigation buttons - absolute positioned, above video */}
        <div 
          className="absolute top-0 left-0 right-0 flex justify-between items-center z-40 p-3 md:p-4"
          onClick={(e) => e.stopPropagation()}
        >
          <Button variant="secondary" size="icon" className="h-9 w-9 md:h-10 md:w-10 shadow-lg" onClick={onBack}>
            <ChevronLeft className="w-4 h-4 md:w-5 md:h-5" />
          </Button>
          
          <div className="flex items-center gap-1.5 md:gap-2">
            {reportButton}
            {editButton}
            <Button
              variant="secondary"
              size="icon"
              className="h-9 w-9 md:h-10 md:w-10 shadow-lg"
              onClick={(e) => {
                e.stopPropagation();
                onShare();
              }}
            >
              <Share2 className="w-4 h-4 md:w-5 md:h-5" />
            </Button>
            {user && (
              <Button
                variant="secondary"
                size="icon"
                className="h-9 w-9 md:h-10 md:w-10 shadow-lg"
                onClick={(e) => {
                  e.stopPropagation();
                  onToggleFavorite();
                }}
              >
                <Heart className={`w-4 h-4 md:w-5 md:h-5 ${isFavorite ? 'fill-destructive text-destructive' : ''}`} />
              </Button>
            )}
          </div>
        </div>
      </div>

      {/* Content Section - Overlapping the hero image */}
      <div className="container mx-auto max-w-6xl px-4 -mt-20 relative z-10 pb-8">
        {/* Watch Full Video Button - Positioned above the card header */}
        {isVideoBanner && (
          <div className="flex justify-center mb-3">
          <Button
            variant="secondary"
            size="sm"
            className="gap-2 bg-primary/5 hover:bg-primary/10 text-primary/70 border border-primary/10 backdrop-blur-md"
              onClick={() => {
                // Pause the banner video when opening modal
                if (videoRef.current) {
                  videoRef.current.pause();
                }
                setVideoModalOpen(true);
              }}
            >
              <Play className="w-4 h-4" />
              {t("restaurants.clickWatchFullVideo", "点击观看完整视频")}
            </Button>
          </div>
        )}

        {/* Unified Card Container */}
        {/* Unified Card Container */}
        <Card className="shadow-xl border-border/50">
          {/* Title Section */}
          <CardHeader className="pb-4 md:pb-6">
            <div className="flex flex-wrap items-center gap-2 mb-1.5 md:mb-2">
              <Badge variant="secondary" className="text-[10px] md:text-xs gap-1 bg-primary/10 text-primary border-primary/20">
                {(restaurant.template === 'michelin' || restaurant.michelin_stars) ? t("admin.templateMichelin", "Michelin") : t("admin.templateGhost", "Virtual Kitchen")}
                <Ghost className="w-3 h-3" />
              </Badge>
              {/* Michelin star designation badge */}
              {restaurant.michelin_stars && (() => {
                const starLabels: Record<string, Record<string, string>> = {
                  "3": { zh: "三星", en: "Three Stars", pt: "Três Estrelas", ar: "ثلاث نجوم", ja: "三つ星", ko: "쓰리스타", fr: "Trois Étoiles", de: "Drei Sterne", es: "Tres Estrellas", it: "Tre Stelle", ru: "Три звезды" },
                  "2": { zh: "二星", en: "Two Stars", pt: "Duas Estrelas", ar: "نجمتان", ja: "二つ星", ko: "투스타", fr: "Deux Étoiles", de: "Zwei Sterne", es: "Dos Estrellas", it: "Due Stelle", ru: "Две звезды" },
                  "1": { zh: "一星", en: "One Star", pt: "Uma Estrela", ar: "نجمة واحدة", ja: "一つ星", ko: "원스타", fr: "Une Étoile", de: "Ein Stern", es: "Una Estrella", it: "Una Stella", ru: "Одна звезда" },
                  "bib_gourmand": { zh: "必比登推介", en: "Bib Gourmand", pt: "Bib Gourmand", ar: "بيب غورماند", ja: "ビブグルマン", ko: "빕 구르망", fr: "Bib Gourmand", de: "Bib Gourmand", es: "Bib Gourmand", it: "Bib Gourmand", ru: "Биб Гурман" },
                  "selected": { zh: "米其林入选", en: "Michelin Selected", pt: "Michelin Selected", ar: "اختيار ميشلان", ja: "ミシュランセレクション", ko: "미슐랭 셀렉션", fr: "Michelin Sélection", de: "Michelin Auswahl", es: "Michelin Selección", it: "Michelin Selected", ru: "Мишлен Выбор" },
                };
                const entry = starLabels[restaurant.michelin_stars];
                const label = entry ? (entry[i18n.language] || entry.en) : null;
                if (!label) return null;
                return (
                  <Badge className="text-[10px] md:text-xs bg-[#C1282D] text-white border-0">
                    {t("admin.templateMichelin", "Michelin")} · {label}
                  </Badge>
                );
              })()}
              {localizedRestaurant.type && localizedRestaurant.type.length > 0 && (() => {
                const rawTypes = Array.isArray(localizedRestaurant.type) ? localizedRestaurant.type : [localizedRestaurant.type];
                const genericMichelinTags = new Set(["米其林", "Michelin"]);
                const starDupTags = new Set(["一星", "二星", "三星", "必比登推介", "米其林入选",
                  "One Michelin Star", "Two Michelin Stars", "Three Michelin Stars",
                  "Uma Estrela Michelin", "Duas Estrelas Michelin", "Três Estrelas Michelin",
                  "Bib Gourmand", "Michelin Selected"]);
                const cleanTypes = rawTypes.filter((t: string) => !genericMichelinTags.has(t) && !starDupTags.has(t) && !/米其林.*星/.test(t));
                if (cleanTypes.length === 0) return null;
                return (
                  <Badge variant="secondary" className="text-[10px] md:text-xs bg-primary/10 text-primary border-primary/20">
                    {cleanTypes.map((tag: string) => getTypeDisplayLabel(tag, i18n.language)).join(" · ")}
                  </Badge>
                );
              })()}
              <p className="text-[10px] md:text-xs font-medium tracking-[0.15em] md:tracking-[0.2em] uppercase text-primary">
                {t("restaurants.exclusiveInterview", "专属故事")}
              </p>
            </div>
            <CardTitle className="text-2xl sm:text-3xl md:text-4xl lg:text-5xl font-bold text-foreground leading-tight">
              {formatTrademarkSymbols(translatedName || localizedRestaurant.name)}
            </CardTitle>
            {/* Translate chip - unified position matching regular restaurants */}
            {onTranslate && (
              <div className="flex items-center gap-3 mt-2 flex-wrap">
                <button
                  className={`inline-flex items-center gap-1 min-h-[32px] py-1 px-2 rounded-md text-xs font-medium transition-all duration-200 active:scale-95 ${
                    isTranslating 
                      ? "text-muted-foreground cursor-wait" 
                      : showTranslation 
                        ? "text-primary bg-primary/10" 
                        : "text-muted-foreground hover:text-primary active:text-primary"
                  }`}
                  disabled={isTranslating}
                  onClick={onTranslate}
                >
                  {isTranslating ? (
                    <Loader2 className="h-3.5 w-3.5 animate-spin" />
                  ) : showTranslation ? (
                    <RotateCcw className="h-3.5 w-3.5" />
                  ) : (
                    <Languages className="h-3.5 w-3.5" />
                  )}
                  <span>
                    {isTranslating 
                      ? t("translate.translating", "翻译中...") 
                      : showTranslation 
                        ? t("translate.showOriginal", "显示原文") 
                        : t("translate.button", "翻译")}
                  </span>
                </button>
              </div>
            )}
          </CardHeader>

          <CardContent className="pt-0">
            {/* Grid Layout inside the unified card */}
            <div className="grid grid-cols-1 md:grid-cols-5 gap-5 md:gap-6 lg:gap-8 md:items-stretch">
              {/* Left: Signature Dish Image + Philosophy - Takes 3 cols on md+ */}
              <div className="md:col-span-3 flex flex-col gap-5 md:gap-6">
                {/* Signature Dish Image */}
                <SignatureDishWithNeijing
                  restaurant={restaurant}
                  localizedRestaurant={localizedRestaurant}
                />

                {/* Food Philosophy */}
                {(truncatedFoodDesc || foodDescription) && (
                  <FoodPhilosophySection 
                    foodDescription={foodDescription}
                    cleanFoodDesc={cleanFoodDesc}
                  />
                )}
              </div>

              {/* Right: Owner Profile Section - Takes 2 cols on md+ */}
              <div className="md:col-span-2 space-y-5 md:space-y-6">
                <div className="bg-muted/30 rounded-2xl border border-border/30 overflow-hidden">
                  {/* Owner Avatar - Centered Circle */}
                  <div className="relative pt-6 md:pt-8 pb-4 md:pb-6 px-4 md:px-6 bg-gradient-to-b from-primary/5 to-transparent">
                    <div className="flex justify-center">
                      <div className="relative">
                        <div 
                          className={`w-20 h-20 sm:w-24 sm:h-24 md:w-28 md:h-28 rounded-full overflow-hidden border-4 border-background shadow-xl ring-4 ring-primary/10 ${restaurant.owner_avatar_url ? 'cursor-pointer' : ''}`}
                          onClick={() => {
                            if (restaurant.owner_avatar_url) setAvatarPreviewOpen(true);
                          }}
                        >
                          {restaurant.owner_avatar_url ? (
                            <img 
                              src={restaurant.owner_avatar_url} 
                              alt={localizedRestaurant.name}
                              className="w-full h-full object-cover"
                            />
                          ) : (
                            <div className="w-full h-full bg-gradient-to-br from-primary/30 via-accent/20 to-muted flex items-center justify-center">
                              <span className="text-3xl sm:text-4xl md:text-5xl font-bold text-primary/70">
                                {avatarFallback}
                              </span>
                            </div>
                          )}
                        </div>
                        {/* Badge */}
                        <Badge className="absolute -bottom-1 left-1/2 -translate-x-1/2 bg-primary text-primary-foreground border-0 px-2 md:px-3 py-0.5 md:py-1 text-[10px] md:text-xs font-medium shadow-lg whitespace-nowrap">
                          <Sparkles className="w-2.5 h-2.5 md:w-3 md:h-3 mr-0.5 md:mr-1" />
                          {t("restaurants.ownerStory", "主理人")}
                        </Badge>
                      </div>
                    </div>
                    {/* Unclaimed hint - need to claim to upload avatar */}
                    {(restaurant as any).store_level === 'shell' && !restaurant.owner_avatar_url && (
                      <p className="text-[10px] md:text-xs text-muted-foreground/70 mt-2 text-center">
                        {t("restaurants.claimToUploadAvatar", "认领店铺后即可上传头像")}
                      </p>
                    )}
                  </div>

                  {/* Owner Info */}
                  <div className="px-4 md:px-6 py-3 md:py-4 text-center border-b border-border/30">
                    <h3 className="text-lg md:text-xl font-bold text-foreground">
                      {formatTrademarkSymbols(getLocalizedField(restaurant, "owner_name") || localizedRestaurant.name)}
                    </h3>
                    <p className="text-[10px] md:text-xs text-muted-foreground font-medium tracking-wider uppercase mt-0.5 md:mt-1">
                      {t("restaurants.chef", "大厨")}
                    </p>
                  </div>

                  {/* Owner Story */}
                  <div className="p-4 md:p-6 space-y-3 md:space-y-4">
                    <div className="flex items-center justify-between">
                      <h4 className="text-xs md:text-sm font-semibold text-foreground flex items-center gap-1.5 md:gap-2">
                        <Quote className="w-3 h-3 md:w-4 md:h-4 text-primary rotate-180" />
                        {t("restaurants.ownerWords", "主理人故事")}
                      </h4>
                      {!isCoreLang && ownerBio && (
                        <button
                          onClick={(e) => { e.stopPropagation(); handleTranslateBio(); }}
                          disabled={isTranslatingBio}
                          className="inline-flex items-center gap-1 px-2 py-0.5 rounded text-[11px] font-medium text-primary hover:bg-primary/10 transition-colors disabled:opacity-50"
                        >
                          {isTranslatingBio ? (
                            <Loader2 className="w-3 h-3 animate-spin" />
                          ) : (
                            <Languages className="w-3 h-3" />
                          )}
                          {isTranslatingBio
                            ? t("common.translating", "翻译中...")
                            : manualBioTranslation?.showTranslated
                              ? t("common.showOriginal", "显示原文")
                              : t("common.translate", "翻译")}
                        </button>
                      )}
                    </div>
                    
                    {displayBio ? (
                      <div className="space-y-2 md:space-y-3">
                        <p className="text-xs md:text-sm text-muted-foreground leading-relaxed">
                          {truncatedBio}
                        </p>
                        {shouldShowViewMore && (
                          <OwnerBioDrawer
                            ownerBio={displayBio}
                            ownerName={localizedRestaurant.name}
                            ownerAvatarUrl={restaurant.owner_avatar_url}
                            avatarFallback={avatarFallback}
                          />
                        )}
                      </div>
                    ) : (
                      <p className="text-xs md:text-sm text-muted-foreground/60 italic">
                        {t("restaurants.noBioYet", "暂无简介")}
                      </p>
                    )}
                  </div>

                  {/* Decorative bottom */}
                  <div className="h-1.5 md:h-2 bg-gradient-to-r from-primary/20 via-primary/40 to-primary/20" />
                </div>

                {/* Recent Posts Section - below owner profile card */}
                <GhostRestaurantRecentPosts restaurantId={restaurant.id} />
              </div>
            </div>
          </CardContent>
        </Card>
      </div>

      {/* Video Modal */}
      {isVideoBanner && (
        <GhostRestaurantVideoModal
          open={videoModalOpen}
          onOpenChange={setVideoModalOpen}
          videoUrl={restaurant.promo_video_url}
          posterUrl={videoPoster}
          title={localizedRestaurant.name}
        />
      )}

      {restaurant.owner_avatar_url && (
        <ImagePreviewModal
          imageUrl={restaurant.owner_avatar_url}
          isOpen={avatarPreviewOpen}
          onClose={() => setAvatarPreviewOpen(false)}
          disableLongImage
        />
      )}
    </div>
  );
};

export default GhostRestaurantHero;
