import { useEffect, useState } from "react";
import { useTranslation } from "react-i18next";
import { supabase } from "@/integrations/supabase/client";
import { useLocalizedContent } from "@/hooks/useLocalizedContent";
import { ChevronDown, ChevronUp, Utensils, Languages, Loader2 } from "lucide-react";

interface Dish {
  id: string;
  dish_name_zh: string;
  dish_name_en: string | null;
  dish_name_pt: string | null;
  description_zh: string | null;
  description_en: string | null;
  description_pt: string | null;
  neijing_zh: string | null;
  neijing_en: string | null;
  neijing_pt: string | null;
  image_url: string | null;
  sort_order: number;
}

interface ChefRecommendedDishesProps {
  restaurantId: string;
}

export const ChefRecommendedDishes = ({ restaurantId }: ChefRecommendedDishesProps) => {
  const { t, i18n } = useTranslation();
  const { currentLang } = useLocalizedContent();
  const [dishes, setDishes] = useState<Dish[]>([]);
  const [loading, setLoading] = useState(true);
  const [expandedDish, setExpandedDish] = useState<string | null>(null);
  // Neijing translation state: { [dishId]: { text, showTranslated } }
  const [neijingTranslations, setNeijingTranslations] = useState<Record<string, { text: string; showTranslated: boolean }>>({});
  const [translatingDishId, setTranslatingDishId] = useState<string | null>(null);

  useEffect(() => {
    const fetchDishes = async () => {
      const { data, error } = await supabase
        .from("chef_recommended_dishes" as any)
        .select("*")
        .eq("restaurant_id", restaurantId)
        .order("sort_order");

      if (!error && data && data.length > 0) {
        setDishes(data as any);
      }
      setLoading(false);
    };
    fetchDishes();
  }, [restaurantId]);

  if (loading || dishes.length === 0) return null;

  const getField = (dish: Dish, field: string): string => {
    // Neijing should always display in Chinese (cultural authenticity rule)
    if (field === "neijing") {
      return (dish as any)["neijing_zh"] || (dish as any)["neijing_en"] || (dish as any)["neijing_pt"] || "";
    }
    // Try user's language first
    const value = (dish as any)[`${field}_${currentLang}`];
    if (value) return value;
    // Fall back to en, then zh
    return (dish as any)[`${field}_en`] || (dish as any)[`${field}_zh`] || (dish as any)[`${field}_pt`] || "";
  };

  const handleTranslateNeijing = async (dish: Dish) => {
    const existing = neijingTranslations[dish.id];
    if (existing) {
      // Toggle between original and translated
      setNeijingTranslations(prev => ({
        ...prev,
        [dish.id]: { ...prev[dish.id], showTranslated: !prev[dish.id].showTranslated }
      }));
      return;
    }

    const neijingZh = getField(dish, "neijing");
    if (!neijingZh) return;

    setTranslatingDishId(dish.id);
    try {
      const { data, error } = await supabase.functions.invoke('translate-content', {
        body: { text: neijingZh, targetLang: i18n.language }
      });
      if (!error && data?.translatedText) {
        setNeijingTranslations(prev => ({
          ...prev,
          [dish.id]: { text: data.translatedText, showTranslated: true }
        }));
      }
    } catch {}
    setTranslatingDishId(null);
  };

  const isCoreLang = currentLang === "zh";

  return (
    <section className="py-8 md:py-12">
      <div className="container mx-auto max-w-4xl px-4">
        {/* Section Header */}
        <div className="text-center mb-6 md:mb-8">
          <p className="text-[10px] md:text-xs font-medium tracking-[0.2em] uppercase text-primary mb-2">
            {t("chef.recommendedDishes", "主厨推荐")}
          </p>
          <h2 className="text-xl md:text-2xl font-bold text-foreground flex items-center justify-center gap-2">
            <Utensils className="w-5 h-5 md:w-6 md:h-6 text-primary" />
            {t("chef.signatureDishes", "招牌菜品")}
          </h2>
          <p className="text-xs md:text-sm text-muted-foreground mt-2">
            {t("chef.dishesWithNeijing", "每道菜品附《黄帝内经》养生解读")}
          </p>
        </div>

        {/* Dishes List */}
        <div className="space-y-4">
          {dishes.map((dish, index) => {
            const isExpanded = expandedDish === dish.id;
            const dishName = getField(dish, "dish_name");
            const description = getField(dish, "description");
            const neijing = getField(dish, "neijing");
            const neijingState = neijingTranslations[dish.id];
            const displayNeijing = neijingState?.showTranslated ? neijingState.text : neijing;
            const isTranslating = translatingDishId === dish.id;

            return (
              <div
                key={dish.id}
                className="rounded-xl border border-border/50 bg-card overflow-hidden transition-all duration-300 hover:border-primary/30 hover:shadow-sm"
              >
                {/* Dish Header */}
                <button
                  className="w-full flex items-center gap-3 md:gap-4 p-4 md:p-5 text-left cursor-pointer"
                  onClick={() => setExpandedDish(isExpanded ? null : dish.id)}
                >
                  <div className="shrink-0 w-8 h-8 md:w-10 md:h-10 rounded-full bg-primary/10 flex items-center justify-center">
                    <span className="text-sm md:text-base font-bold text-primary">{index + 1}</span>
                  </div>
                  <div className="flex-1 min-w-0">
                    <h3 className="text-sm md:text-base font-semibold text-foreground truncate">
                      {dishName}
                    </h3>
                    {!isExpanded && description && (
                      <p className="text-xs text-muted-foreground mt-0.5 flex items-center">
                        <span className="line-clamp-1">{description}</span>
                        <span 
                          onClick={(e) => {
                            e.stopPropagation();
                            setExpandedDish(dish.id);
                          }}
                          className="shrink-0 ml-1 text-primary font-medium underline cursor-pointer hover:text-primary/80"
                        >
                          {t("chef.healthReading", "Health Reading")}
                        </span>
                      </p>
                    )}
                  </div>
                  <div className="shrink-0 text-muted-foreground">
                    {isExpanded ? <ChevronUp className="w-4 h-4" /> : <ChevronDown className="w-4 h-4" />}
                  </div>
                </button>

                {/* Expanded Content */}
                {isExpanded && (
                  <div className="px-4 md:px-5 pb-4 md:pb-5 space-y-4 animate-in fade-in slide-in-from-top-2 duration-200">
                    {dish.image_url && (
                      <div className="rounded-lg overflow-hidden aspect-video">
                        <img src={dish.image_url} alt={dishName} className="w-full h-full object-cover" />
                      </div>
                    )}
                    {description && (
                      <div className="bg-muted/50 rounded-lg p-3 md:p-4">
                        <p className="text-xs md:text-sm font-semibold text-foreground mb-1.5 flex items-center gap-1.5">
                          <span>🍽️</span> {t("chef.dishDescription", "菜品介绍")}
                        </p>
                        <p className="text-sm leading-relaxed text-foreground/90">{description}</p>
                      </div>
                    )}

                    {/* Huangdi Neijing Interpretation */}
                    {neijing && (
                      <div className="bg-white dark:bg-zinc-900 border-2 border-foreground/20 dark:border-zinc-600 rounded-lg p-4 md:p-5 shadow-sm">
                        <div className="flex items-center justify-between mb-3">
                          <p className="text-xs md:text-sm font-bold text-foreground flex items-center gap-1.5">
                            <span>📜</span>
                            {t("chef.neijingInterpretation", "《黄帝内经》解读")}
                          </p>
                          {/* Translate button - hide for Chinese users */}
                          {!isCoreLang && (
                            <button
                              onClick={(e) => {
                                e.stopPropagation();
                                handleTranslateNeijing(dish);
                              }}
                              disabled={isTranslating}
                              className="inline-flex items-center gap-1 px-2 py-0.5 rounded text-[11px] font-medium text-primary hover:bg-primary/10 transition-colors disabled:opacity-50"
                            >
                              {isTranslating ? (
                                <Loader2 className="w-3 h-3 animate-spin" />
                              ) : (
                                <Languages className="w-3 h-3" />
                              )}
                              {isTranslating
                                ? t("common.translating", "翻译中...")
                                : neijingState?.showTranslated
                                  ? t("common.showOriginal", "显示原文")
                                  : t("common.translate", "翻译")}
                            </button>
                          )}
                        </div>
                        <p className="text-sm leading-[1.8] text-foreground font-medium">
                          {displayNeijing}
                        </p>
                      </div>
                    )}
                  </div>
                )}
              </div>
            );
          })}
        </div>
      </div>
    </section>
  );
};
